-- W1.6 questions batch 4881/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6e2f88c7-moex-00002', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '幫派老大甲某日與女友去某餐廳吃飯，在門口處與他人發生糾紛，對方
人多勢眾，甲被打倒在地，女友見狀趕快在 Line群組發「老大在某餐廳
被打，趕快來救他」之訊息，乙、丙為幫派成員，兩人看到訊息後立刻
一起搭車趕往該餐廳，乙下車後立刻掏槍，丙見乙手上有槍，怕事情鬧
大，趁亂悄悄離開。乙與對方爭吵後，向架住老大甲的丁開槍，丁當場
遭擊斃。試問乙、丙該如何論處？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "7f120bd1adeb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0914", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00003', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲近來因身體不好、事業不順等問題甚為煩惱，經人介紹與某號稱「大
師」之乙認識，乙對甲說，甲之身體內有許多髒東西，需其透過神通以
性交方式進入甲之體內將之取出，否則甲會有更大厄運降臨。甲考慮數
日後，同意與乙發生性關係以求改運。試問乙該如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "7f120bd1adeb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0914", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00004', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲、乙某日相約至市立公園約會，一時興起，至林蔭深處發生性關係，
未料丙恰好也在附近，發現後即躲在樹後用手機偷錄甲、乙的親密畫面。
試問丙該如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "7f120bd1adeb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0914", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00005', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲起訴乙，聲明被告乙應返還動產 A物予原告甲，請求法院就侵權損害
賠償請求權及不當得利返還請求權擇一為判決。就原告主張的侵權損害
賠償請求權，受訴法院認為有理由；就不當得利返還請求權，原告的舉
證未能使受訴法院獲得確信心證。受訴法院僅依侵權行為規定，判決命
被告乙返還動產 A 物予原告。判決確定後一年，乙仍未將 A 物返還予
甲，甲又依不當得利規定，向乙住所地的法院起訴，請求法院判決命被
告乙將 A物返還予原告甲。對於甲的再次起訴，受訴法院應如何裁判？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "946f3a21d9f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0912", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00006', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '丙向管轄法院起訴乙，請求被告乙返還不當得利新臺幣（以下同）300 萬
元及其利息予被繼承人甲的共同繼承人丙、丁。丙主張：被告乙女為甲
入住 A安養中心前的同居人，其未告知甲的子女丙、丁，私自將甲遷到
B 安養中心；乙於甲住於安養中心期間，私自拿取甲的存摺、印章及提
款卡，自甲的某銀行帳戶提領共300 萬元，甲於今年初過世後，其共同
繼承人丙、丁整理甲的遺產，始察知乙提款一事，現依不當得利規定請
求返還。被告乙則以甲同意其提款供作生活、醫藥、看護等費用為抗辯。
試問：丙的起訴是否合法？就乙得利有無法律上原因的要件事實，應由
何人負舉證責任？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "946f3a21d9f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0912", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00007', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲因涉嫌觸犯刑法第 226 條之 1強制猥褻而故意殺被害人罪，經目擊證
人乙報案後旋即遭警方逮捕，於警方依刑事訴訟法第 95 條對甲為權利
告知後，甲即表示放棄緘默權，警方遂開始詢問甲涉案情節。試問：依
113 年憲判字第8 號
如甲於警詢中自白犯罪，惟於審判中否認犯罪，則甲之警詢筆錄是否
有證據能力？（12 分）
如甲表示沒錢延聘律師，警方於警詢中應否為甲指定辯護人？（13 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "946f3a21d9f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0912", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00008', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲因重傷罪遭地方法院判處有期徒刑七年，甲上訴後經高等法院判決駁
回，本案因當事人均未再上訴而告確定。試問：
如乙為本案一審受命法官，於甲提再審時，應否迴避？（12 分）
如乙為本案二審陪席法官，於甲提再審時，應否迴避？（13 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "946f3a21d9f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0912", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00009', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'essay', '甲因家中冰箱故障至乙商場選購新冰箱，當場展示之具有自動製冰功能
的冰箱甚符合甲之心意，經詢問賣場工作人員，得知該型號目前缺貨中，
要 1 個月後才會到貨。甲心急如焚，遂詢問可否將展示品 A 冰箱帶回
家。甲認為 A冰箱在現場冰箱門已經經多人開合，門把上多處留有使用
痕跡，雖不影響使用但和全新品仍有差距，遂商請乙予以折扣。工作人
員表示，可以賣給甲，但因為 A冰箱只是展示並未被實際插電試用，只
願意折價新臺幣500 元。最後甲因為家中沒有冰箱確實不便，遂同意以
折價新臺幣 500元之價格購入 A冰箱，並當場載回家。詎料，回家使用
後，第 2天便發現 A冰箱除了製冰盒無法如同廣告宣稱的自動製冰外，
其他功能一切正常，但甲之所以屬意 A冰箱，就是因為其有自動製冰功
能，夏天隨時可以在飲料中加冰塊。於是甲便主張因 A有瑕疵要退貨，
要求乙換一台同型號的全新冰箱給甲。試附理由說明，甲的主張是否有
理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0904", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00010', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'essay', '甲租用乙所有的 A 地建築房屋，於租賃關係存續中，乙將 A 地出賣予
丙，買賣契約（以下稱系爭契約）中約定，「雙方同意，若丙方以本契約
標的申請銀行貸款，核貸結果未能達本契約約定價金之 7 成，則合約無
效」。甲得知後，主張有優先承買權，乙表示系爭契約係約定丙能順利取
得貸款，作為生效條件，為附條件之買賣契約；丙是否能順利取得貸款
乃將來客觀不確定事實，甲無從主張優先承買權。試附理由說明，甲可
否主張優先承買權？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0904", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00011', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲與乙為同一棟社區之住戶，甲住8樓，乙住7樓，甲生性愛熱鬧，常常邀約親朋好友到家作客， 並大聲喧嘩，甚至已半夜時分仍在家中高歌作樂。下列敘述，何者錯誤？', '["在他人居住區域，發出超越一般人社會生活所能忍受之噪音，屬不法侵害他人居住安寧之人格 利益", "人格利益至高無上，不容侵犯，只要遭受侵害，不問程度如何，被害人均得依民法第195條第 1項有關人格及身分法益侵害規定，請求賠償相當之金額", "如果長期、持續性噪音，已使人因此無法入眠，健康受損，可能構成健康權之侵害", "健康權屬於特別人格權，若受侵害，被害人得請求非財產上之金錢賠償 23520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:43+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
